import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "What day of the week was January 1, 2000?", a: "January 1, 2000 was a Saturday. The year 2000 was also notable as the last year of the 20th century and the year many feared the Y2K computer bug - which ultimately had minimal impact." },
  { q: "How is the day of the week calculated mathematically?", a: "The most famous algorithm is Zeller's congruence, which uses modular arithmetic to compute the day from any date. Another is the Doomsday algorithm by mathematician John Conway, which uses anchor days for each year. This calculator uses JavaScript's built-in Date object, which accurately handles all edge cases including leap years." },
  { q: "What is the Gregorian calendar?", a: "The Gregorian calendar is the international standard calendar used in most of the world today. It was introduced by Pope Gregory XIII in 1582 to correct drift in the Julian calendar. It has 365 days per year with a leap year every 4 years, except for century years not divisible by 400." },
  { q: "What day of the week were you born on?", a: "Enter your birthdate in the calculator to find out which day of the week you were born. Many people find this surprising - often we assume we know, but looking it up reveals otherwise. Statistically, births are roughly evenly distributed across all seven days." },
  { q: "What is the most common day for births?", a: "Tuesday is statistically the most common birth day in the US, primarily because many scheduled C-sections and induced labors occur on weekdays. Sunday is the least common day for births. When looking at natural (unscheduled) births only, the distribution is much more even." },
  { q: "What day does Christmas fall on in the coming years?", a: "Christmas (December 25): 2025 - Thursday; 2026 - Friday; 2027 - Saturday; 2028 - Monday; 2029 - Tuesday; 2030 - Wednesday. Christmas falls on a Sunday approximately once every 7 years on average." },
  { q: "What is the Doomsday algorithm?", a: "The Doomsday algorithm, invented by mathematician John Conway, lets you mentally calculate the day of any date. It works by memorizing that certain easy-to-remember dates always fall on the same day of the week within any given year (called the 'Doomsday'). For 2025, the Doomsday is Thursday." },
  { q: "How does a leap year affect the day of the week?", a: "Leap years add one extra day (February 29), which shifts all subsequent days of the year by one day compared to a non-leap year. A date in March through December of a leap year falls one day later in the week than the same date in a common year." },
];

const NOTABLE_DATES = [
  ["July 4, 1776", "Thursday", "US Declaration of Independence"],
  ["December 7, 1941", "Sunday", "Attack on Pearl Harbor"],
  ["November 22, 1963", "Friday", "JFK assassination"],
  ["July 20, 1969", "Sunday", "Moon landing (Apollo 11)"],
  ["September 11, 2001", "Tuesday", "9/11 terrorist attacks"],
  ["January 20, 2025", "Monday", "Trump second inauguration"],
];

const DAYS = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];
const MONTHS = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];

export default function DayOfWeekCalculator() {
  const today = new Date();
  const pad = (n: number) => String(n).padStart(2, "0");
  const [date, setDate] = useState(`${today.getFullYear()}-${pad(today.getMonth() + 1)}-${pad(today.getDate())}`);

  const d = new Date(date + "T12:00:00");
  const valid = !isNaN(d.getTime());
  const dayName = valid ? DAYS[d.getDay()] : "";
  const monthName = valid ? MONTHS[d.getMonth()] : "";
  const isWeekend = valid && (d.getDay() === 0 || d.getDay() === 6);
  const dayNum = valid ? d.getDay() : -1;

  return (
    <>
      <SEOHead
        title="Free Day of the Week Calculator Online - Find Any Date's Weekday Instantly | CalcHive"
        description="Free online day of the week calculator. Find out what day of the week any past or future date falls on instantly. 100% free for everyone, no signup required."
        canonical="/day-of-week-calculator"
        keywords="free day of the week calculator, what day of the week calculator free, find weekday for any date free, day of week finder free online, free date weekday calculator"
        category="Date & Time Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-orange-600 dark:text-orange-400 bg-orange-50 dark:bg-orange-950/50 px-3 py-1 rounded-full mb-4 inline-block">Date &amp; Time</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Day of the Week Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free day of the week calculator to find weekday for any date free, past or future. This what day of the week calculator free also works as a day of week finder free online and free date weekday calculator.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="mb-8">
            <label className="text-sm font-semibold text-foreground mb-2 block">Enter Any Date</label>
            <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full px-4 py-3 rounded-xl border border-border bg-background text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 text-sm" />
          </div>
          {valid && (
            <motion.div key={date} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
              <div className={`bg-gradient-to-br ${isWeekend ? "from-emerald-500 to-emerald-700" : "from-orange-500 to-orange-700"} rounded-2xl p-8 mb-4 text-center shadow-lg`}>
                <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-2">{monthName} {d.getDate()}, {d.getFullYear()}</p>
                <p className="text-5xl font-black text-white tracking-tight" data-testid="result-day">{dayName}</p>
                <p className="text-white/70 text-sm mt-2">{isWeekend ? "Weekend" : "Weekday"}</p>
              </div>
              <div className="flex justify-center gap-2 flex-wrap">
                {DAYS.map((name, i) => (
                  <div key={name} className={`px-4 py-2 rounded-xl text-sm font-semibold border transition-all ${i === dayNum ? "bg-orange-500 text-white border-orange-500" : "bg-accent/60 text-muted-foreground border-border"}`}>
                    {name.slice(0, 3)}
                  </div>
                ))}
              </div>
            </motion.div>
          )}
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Find What Day Any Date Falls On for Free</h2>
          <p className="text-muted-foreground leading-relaxed">The day of the week for any date can be calculated mathematically. The most widely used method for mental calculation is the Doomsday algorithm by John Conway, which uses anchor days. For computers, the Zeller's congruence formula or simply converting a date to a day index works reliably across all years.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Zeller's Congruence (simplified):</p>
            <p>h = (q + -)/5- + K + - + - - 2J) mod 7</p>
            <p className="text-xs text-muted-foreground mt-2">q = day - m = month (March=3...Feb=14) - K = year%100 - J = century</p>
            <p className="text-xs text-muted-foreground">Result: 0=Saturday - 1=Sunday - 2=Monday - 3=Tuesday - 4=Wednesday - 5=Thursday - 6=Friday</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Calculate Weekday for Any Past or Future Date</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Date", "Day of Week", "Event"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {NOTABLE_DATES.map(([date_, day, event]) => (
                  <tr key={date_} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{date_}</td>
                    <td className="py-2.5 px-4 text-orange-600 dark:text-orange-400 font-bold">{day}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{event}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Weekday Finder for Everyone</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Day", "Name Origin", "US Birth Rank", "Notes"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Sunday", "Sun (Latin: dies solis)", "#7 (least)", "Fewest scheduled deliveries"],
                  ["Monday", "Moon (Latin: dies lunae)", "#5", "Most 'Blue Monday' reports"],
                  ["Tuesday", "Tiw (Norse war god)", "#1 (most)", "Most scheduled C-sections"],
                  ["Wednesday", "Woden (Norse chief god)", "#3", "Midweek - balanced"],
                  ["Thursday", "Thor (Norse thunder god)", "#4", "US Thanksgiving always falls here"],
                  ["Friday", "Frigg (Norse goddess)", "#2", "Second most common birth day"],
                  ["Saturday", "Saturn (Roman planet)", "#6", "Few scheduled births"],
                ].map(([day, origin, rank, notes]) => (
                  <tr key={day} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-bold text-orange-600 dark:text-orange-400">{day}</td>
                    <td className="py-2.5 px-4 text-muted-foreground text-xs">{origin}</td>
                    <td className="py-2.5 px-4 text-foreground font-medium">{rank}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{notes}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/day-of-week-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


